#[derive(Debug, Clone, Default)]
pub struct CacheStats {
    /// 缓存条目数量
    pub entry_count: u64,
    /// 命中数
    pub hits: u64,
    /// 未命中数
    pub misses: u64,
    /// 命中率
    pub hit_rate: f64,
    /// 缓存大小
    pub size: u64,
}

impl CacheStats {
    /// 打印统计信息
    pub fn print(&self) {
        println!("DNS 缓存统计:");
        println!("  条目数量: {}", self.entry_count);
        println!("  命中率: {:.2}%", self.hit_rate * 100.0);
        println!("  大小: {}", self.size);
    }
